import{l as e,a as t,c as l,aj as i}from"./chunks/framework.CyPZ6aEA.js";const n=JSON.parse('{"title":"Matt Pocock 技能体验","description":"","frontmatter":{},"headers":[],"relativePath":"ai/matt-pocock-skills.md","filePath":"ai/matt-pocock-skills.md"}'),o={name:"ai/matt-pocock-skills.md"};function r(s,a,c,p,h,u){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="matt-pocock-技能体验" tabindex="-1">Matt Pocock 技能体验 <a class="header-anchor" href="#matt-pocock-技能体验" aria-label="Permalink to &quot;Matt Pocock 技能体验&quot;">​</a></h1><h2 id="why" tabindex="-1">why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;why&quot;">​</a></h2><p>技能愈来愈多，但找到对自己实用的技能还是相当困难，我必须在一堆相似技能中，凭感觉选择一个，然后将 skill 导入到当前 Agent 中，并亲自体验才能知道它的效果。</p><p>这次 Matt Pocock 号称这是自己平时会日用的技能 <a href="https://github.com/mattpocock/skills" target="_blank" rel="noreferrer">mattpocock/skills</a>，他经常在 YouTube 上分享关于 TypeScript 和 AI 编码的深入见解，擅长将复杂的 TypeScript 概念化繁为简，那么他自用的技能也可预见有较好的体验。</p><p>并且作者提到，这些技能易于组合使用，适用于借助 Agent 完成小任务的场景，而非完全的 vibe coding。适合还在逐步过渡到 Agent 开发的人🤡。</p><h2 id="how" tabindex="-1">how <a class="header-anchor" href="#how" aria-label="Permalink to &quot;how&quot;">​</a></h2><p>用于体验此技能的 Agent 主要是两个：</p><ol><li>公司 + MiniMax 2.7</li><li>家中 qodercli + 默认社区订阅计划（免费版）Auto 模型</li></ol><blockquote><p>我使用的都是非流行 Agent，所以无法很好地使用 npx skills 和自定义斜杠命令，体验略差一些。</p></blockquote><h2 id="what" tabindex="-1">what <a class="header-anchor" href="#what" aria-label="Permalink to &quot;what&quot;">​</a></h2><p>下面依据日常使用流程顺序来介绍</p><h3 id="setup-matt-pocock-skills" tabindex="-1">setup-matt-pocock-skills <a class="header-anchor" href="#setup-matt-pocock-skills" aria-label="Permalink to &quot;setup-matt-pocock-skills&quot;">​</a></h3><p>首先通过这个技能来进行初始配置，包含：issue 追踪器（可本地）、issue 分类标签、文档解构等。</p><p>提示词参考：</p><ul><li>/setup-matt-pocock-skills</li><li>执行 setup-matt-pocock-skills 技能</li></ul><h3 id="caveman" tabindex="-1">caveman <a class="header-anchor" href="#caveman" aria-label="Permalink to &quot;caveman&quot;">​</a></h3><p>切换到一种极度精简的沟通模式，通过去掉填充词来减少Token消耗约75%，同时保留全部技术信息。即简要地回答。</p><p>使用时，qodercli 中的 context 百分比仍在快速增加。但 token 消耗和 context 增长没有正相关关系，可能确实有减少 token 消耗。</p><p>提示词参考：</p><ul><li>/caveman</li></ul><h3 id="grill-with-docs" tabindex="-1">grill-with-docs <a class="header-anchor" href="#grill-with-docs" aria-label="Permalink to &quot;grill-with-docs&quot;">​</a></h3><p>与 Agent 对齐编码目标，类似被面试的深入细节探索，并更新文档。若无需更新文档可用 <strong>grill-me</strong> 技能。</p><p>使用时，会更多地让用户补充需求细节，但是对代码仓的自动探索不够充分，能自己查的依然来问我。</p><p>提示词参考：</p><ul><li>/grill-with-docs 我想重构用户认证模块，深入质询我的计划</li><li>使用 grill-with docs 技能评估添加“社交登录”功能的决策树</li></ul><h3 id="grill-me" tabindex="-1">grill-me <a class="header-anchor" href="#grill-me" aria-label="Permalink to &quot;grill-me&quot;">​</a></h3><p>同上，但是不更新文档。</p><blockquote><p>👍检查方案设计问题</p></blockquote><h3 id="to-prd" tabindex="-1">to-prd <a class="header-anchor" href="#to-prd" aria-label="Permalink to &quot;to-prd&quot;">​</a></h3><p>将当前的对话上下文和代码理解，转化为一份结构化的产品需求文档。</p><p>提示词参考：</p><ul><li>/to-prd</li><li>执行 to-prd 技能</li></ul><h3 id="to-issues" tabindex="-1">to-issues <a class="header-anchor" href="#to-issues" aria-label="Permalink to &quot;to-issues&quot;">​</a></h3><p>将计划、规格说明或PRD分解为可独立认领的垂直切片型 issue（代指各种任务：feat/fix 等），并记录到 issue 追踪器。</p><p>提示词参考：</p><ul><li>/to-issues</li><li>使用 to-issues 技能分解任务</li></ul><h3 id="triage" tabindex="-1">triage <a class="header-anchor" href="#triage" aria-label="Permalink to &quot;triage&quot;">​</a></h3><p>通过 setup-matt-pocock-skills 阶段配置的标签来管理 issue。</p><p>提示词参考：</p><ul><li>/triage 显示所有需要我关注的 issue</li><li>/triage 有哪些 issue 已经准备好可以你实现了？</li></ul><h3 id="tdd" tabindex="-1">tdd <a class="header-anchor" href="#tdd" aria-label="Permalink to &quot;tdd&quot;">​</a></h3><p>采用“红-绿-重构”循环的测试驱动开发，开发并验证、调整。</p><p>使用时，前端集成测试还比较困难，开发的代码有问题调整也慢。这个可能与模型更有关系。</p><p>提示词参考：</p><ul><li>/tdd 为“用户重置密码”功能编写测试和实现</li><li>使用 tdd 技能开发每个任务</li></ul><blockquote><p>开发后用 triage 走状态</p></blockquote><h3 id="zoom-out" tabindex="-1">zoom-out <a class="header-anchor" href="#zoom-out" aria-label="Permalink to &quot;zoom-out&quot;">​</a></h3><p>站在全局更高层的视角，来解释选中的代码。</p><p>这个技能体验不错，还会给出一些数据流分析。</p><p>提示词参考：</p><ul><li>/zoom-out 看看这个新模块会如何与现有的通知服务交互</li><li>/zoom-out 解析当前模块职责</li></ul><h3 id="improve-codebase-architecture" tabindex="-1">improve-codebase-architecture <a class="header-anchor" href="#improve-codebase-architecture" aria-label="Permalink to &quot;improve-codebase-architecture&quot;">​</a></h3><p>分析代码库，寻找代码改进目标。</p><p>会给出多个可改进点，选择性改进</p><p>提示词参考：</p><ul><li>/improve-codebase-architecture</li><li>/improve-codebase-architecture 我的订单处理模块越来越臃肿了，用这个技能帮我评估一下如何改进它的架构和可测试性</li></ul><h3 id="diagnose" tabindex="-1">diagnose <a class="header-anchor" href="#diagnose" aria-label="Permalink to &quot;diagnose&quot;">​</a></h3><p>处理顽固错误或性能问题，循环诊断。</p><p>提示词参考：</p><ul><li>/diagnose 登录功能有时会失败，分析下</li><li>/diagnose 分析内存泄漏问题</li></ul><h3 id="write-a-skill" tabindex="-1">write-a-skill <a class="header-anchor" href="#write-a-skill" aria-label="Permalink to &quot;write-a-skill&quot;">​</a></h3><p>创建新的 Agent 技能，遵循正确的结构、渐进式披露原则和配套资源。</p><p>提示词参考：</p><ul><li>/write-a-skill 帮我建立一个新技能，用来生成项目的CHANGELOG</li><li>/write-a-skill 编写一个用于代码审查的新技能</li></ul>',64)])])}const k=e(o,[["render",r]]);export{n as __pageData,k as default};
